// core/types.ts — StepContext (additive method)
joinBranches<TJoin = unknown>(
  branches: Array<{ workflowId: string; input: unknown; key?: string }>,
  options?: {
    policy?: 'all' | 'any' | 'race' | 'allSettled'; // default 'all'
    cancelLosers?: boolean;                          // race/any: cancel still-running branches (default true)
  },
): Promise<TJoin>; // resolves on the SECOND pass after the join quorum is met; never on first call

