New additive exports from `index.ts`:

```ts
// A host-built map of compiled, named, reusable handlers + predicates.
interface HandlerRegistry<TContext = Record<string, unknown>> {
  handlers: Record<string, StepHandler<unknown, TContext>>;           // name -> compiled fn
  compensations?: Record<string, StepHandler<unknown, TContext>>;     // name -> compiled fn
  predicates?: Record<string, (ctx: TContext, run: WorkflowRun) => boolean | Promise<boolean>>;
  contextFactories?: Record<string, (input: unknown) => TContext>;    // named context builders
}

// The data shape extends the EXISTING WorkflowDefinitionDoc.steps[] entry:
interface DefinitionStepRef {
  id: string;
  handler: string;          // REQUIRED: key into registry.handlers — selection only
  retries?: number;
  timeout?: number;
  retryDelay?: number;
  retryBackoff?: 'exponential' | 'linear' | 'fixed' | number;
  conditionRef?: string;    // key into registry.predicates (replaces serialized `condition` string)
  skipIfRef?: string;
  runIfRef?: string;
  compensateRef?: string;   // key into registry.compensations
  // I/O wiring stays declarative + non-Turing-complete: no expressions.
  // inputs is metadata only; handlers still read via ctx.getOutput.
}

// Hydrate a stored definition into the same Workflow object createWorkflow returns.
function createWorkflowFromDefinition<TContext, TInput = unknown>(
  def: WorkflowDefinitionDoc,
  registry: HandlerRegistry<TContext>,
  opts?: { container?: StreamlineContainer; contextFactory?: string },
): Workflow<TContext, TInput>;

// Convenience loader: fetch a stored version + hydrate in one call.
function loadWorkflowFromStore<TContext, TInput = unknown>(
  workflowId: string,
  registry: HandlerRegistry<TContext>,
  opts?: { version?: string; container?: StreamlineContainer },
): Promise<Workflow<TContext, TInput>>;
```

Errors (extend existing `HttpError`-shaped hierarchy): `UnknownHandlerError` (400, code `streamline.definition.unknown_handler`) when a `handler`/`*Ref` name is absent from the registry; `InvalidDefinitionError` (400) for malformed step refs. Both thrown at hydration time, never at run time.

New ctx.* primitives on StepContext (core/types.ts:295-457) + StepContextImpl (context.ts):

interface InjectableStep { stepId: string; handlerKey: string; input?: unknown; }
ctx.injectSteps(steps: InjectableStep[], opts?: { position?: 'after-current' | 'end' }): Promise<void>
  // Appends StepState entries into run.steps + a per-run graphOverlay (new run field). handlerKey must
  // resolve in a NEW per-engine handler registry (define.ts: config.dynamicHandlers: Record<string, StepHandler>).
  // Engine NEVER deserializes code — handlerKey only SELECTS a pre-registered in-code handler (named-handler
  // registry rule). Idempotent: re-inject with same stepIds is a no-op (dedupe on stepId).

interface LoopControl<S> { state: S; done: boolean; }
ctx.loop<S>(init: S, body: (state: S, iter: number) => Promise<LoopControl<S>>, opts?: { maxIterations?: number }): Promise<S>
  // Durable iterator. After each body() resolves, the returned {state,done} is checkpointed
  // (reuses ctx.checkpoint slot, see durability). Resume replays from last checkpointed iteration —
  // body() for completed iterations is NOT re-invoked. maxIterations caps unbounded tool-loops.

ctx.spawnAgents(children: Array<{ workflowId: string; input: unknown }>, opts?: { concurrency?: number; joinPolicy?: 'all' | 'first' | 'allSettled' }): Promise<unknown[]>
  // Durable fan-out of child workflows. Built on existing childWorkflow WaitSignal + scatter checkpoint.
  // Stores childRunIds in a checkpoint; parent parks (zero compute) until join condition met.
  // Cancellation propagates: engine.cancel(parent) walks stored childRunIds and cancels each.

interface GateToken { gateId: string; runId: string; stepId: string; reason: string; data?: unknown; }
ctx.gate(reason: string, data?: unknown): Promise<unknown>   // opens a durable human-approval gate, parks the run
engine.resolveGate(gateId: string, decision: unknown): Promise<WorkflowRun>   // public engine method
ctx.resolveGate(gateId: string, decision: unknown): Promise<void>   // lets ONE agent run resolve ANOTHER run's gate

ctx.stream(frame: unknown): void   // fire-and-forget partial-progress; NON-durable. New 'step:progress' event.

